CREATE TABLE IF NOT EXISTS forecast_origin_distributions (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, horizon INTEGER NOT NULL, model_version TEXT NOT NULL, lower REAL, upper REAL, target_alpha REAL, interval_method TEXT, interval_width REAL, quantiles_json TEXT NOT NULL, payload_json TEXT NOT NULL, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE(run_id,origin_candle_time,horizon,model_version));
CREATE TABLE IF NOT EXISTS horizon_settlements (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, horizon INTEGER NOT NULL, maturity_time TEXT, actual REAL, covered INTEGER, absolute_error REAL, interval_score REAL, settlement_status TEXT NOT NULL, payload_json TEXT NOT NULL, UNIQUE(run_id,origin_candle_time,horizon));
CREATE TABLE IF NOT EXISTS conformal_calibration_state (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, horizon INTEGER NOT NULL, origin_candle_time TEXT NOT NULL, method TEXT NOT NULL, target_alpha REAL, rolling_coverage REAL, coverage_debt REAL, payload_json TEXT NOT NULL, UNIQUE(run_id,horizon,origin_candle_time));
CREATE TABLE IF NOT EXISTS quantile_forecasts (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, horizon INTEGER NOT NULL, quantile REAL NOT NULL, value REAL NOT NULL, model_version TEXT NOT NULL, UNIQUE(run_id,origin_candle_time,horizon,quantile,model_version));
CREATE TABLE IF NOT EXISTS model_origin_weights (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, horizon INTEGER NOT NULL, quantile REAL NOT NULL, model_name TEXT NOT NULL, weight REAL NOT NULL, UNIQUE(run_id,origin_candle_time,horizon,quantile,model_name));
CREATE TABLE IF NOT EXISTS probabilistic_scores (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, horizon INTEGER NOT NULL, model_version TEXT NOT NULL, crps REAL, crps_method TEXT, mae REAL, rmse REAL, direction_brier REAL, interval_score REAL, coverage REAL, sharpness REAL, payload_json TEXT NOT NULL, UNIQUE(run_id,origin_candle_time,horizon,model_version));
CREATE TABLE IF NOT EXISTS regime_probabilities (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, scale TEXT NOT NULL, regime TEXT NOT NULL, probability REAL, model_version TEXT NOT NULL, payload_json TEXT NOT NULL, UNIQUE(run_id,origin_candle_time,scale,regime,model_version));
CREATE TABLE IF NOT EXISTS regime_durations (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, regime TEXT NOT NULL, age INTEGER, expected_total REAL, expected_remaining REAL, payload_json TEXT NOT NULL, UNIQUE(run_id,origin_candle_time,regime));
CREATE TABLE IF NOT EXISTS drift_events (id INTEGER PRIMARY KEY AUTOINCREMENT, event_hash TEXT NOT NULL UNIQUE, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, state TEXT NOT NULL, payload_json TEXT NOT NULL, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS meta_label_outcomes (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, primary_side TEXT NOT NULL, meta_label TEXT NOT NULL, actionability_probability REAL, payload_json TEXT NOT NULL, UNIQUE(run_id,origin_candle_time));
CREATE TABLE IF NOT EXISTS confidence_set_results (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, horizon INTEGER NOT NULL DEFAULT 0, metric TEXT NOT NULL, regime TEXT NOT NULL DEFAULT '', session TEXT NOT NULL DEFAULT '', volatility_bucket TEXT NOT NULL DEFAULT '', payload_json TEXT NOT NULL, UNIQUE(run_id,origin_candle_time,horizon,metric,regime,session,volatility_bucket));
CREATE TABLE IF NOT EXISTS promotion_gate_results (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, eligible INTEGER NOT NULL DEFAULT 0, payload_json TEXT NOT NULL, UNIQUE(run_id,origin_candle_time));
CREATE TABLE IF NOT EXISTS runtime_metrics (id INTEGER PRIMARY KEY AUTOINCREMENT, run_id TEXT NOT NULL, origin_candle_time TEXT NOT NULL, module TEXT NOT NULL, wall_seconds REAL, peak_memory_bytes INTEGER, payload_json TEXT NOT NULL, UNIQUE(run_id,origin_candle_time,module));
CREATE INDEX IF NOT EXISTS idx_fod_run_time_h ON forecast_origin_distributions(run_id,origin_candle_time,horizon);
CREATE INDEX IF NOT EXISTS idx_hs_status_maturity ON horizon_settlements(settlement_status,maturity_time,horizon);
CREATE INDEX IF NOT EXISTS idx_qf_run_h ON quantile_forecasts(run_id,horizon,origin_candle_time);
CREATE INDEX IF NOT EXISTS idx_ps_model_h ON probabilistic_scores(model_version,horizon,origin_candle_time);
CREATE INDEX IF NOT EXISTS idx_rp_regime_time ON regime_probabilities(regime,origin_candle_time);
CREATE INDEX IF NOT EXISTS idx_de_state_time ON drift_events(state,origin_candle_time);
